// The previous attempt failed at the very first assertion `post1_self_@ =~= post2_self_@`,
// which means the ensures clauses of `push` (post1_self_@ == pre_self_@.push(*new_value), etc.)
// are not visible as outer hypotheses — they live only inside the implication antecedent of
// det_push's ensures. Bring the antecedent into scope as a path condition via an `if`, then
// do the proof inside that branch where every ensures clause of `push` (for both posts) is
// available.

seq_push_lemma::<T>();
seq_push_index_of_lemma::<T>();
assert(pre_self_@.no_duplicates());

if post1_self_.wf()
    && post1_self_@ == pre_self_@.push(*new_value)
    && post1_self_.len() == pre_self_.len() + 1
    && (forall|v: T| #![auto] pre_self_@.contains(v) ==>
            pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v))
    && post1_self_.get_node_ref(*new_value) == r1
    && post1_self_.unique()
    && post2_self_.wf()
    && post2_self_@ == pre_self_@.push(*new_value)
    && post2_self_.len() == pre_self_.len() + 1
    && (forall|v: T| #![auto] pre_self_@.contains(v) ==>
            pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v))
    && post2_self_.get_node_ref(*new_value) == r2
    && post2_self_.unique()
{
    // The ensures clauses are now path conditions; re-introduce the seq lemmas so the
    // contains / index_of facts are available locally.
    seq_push_lemma::<T>();
    seq_push_index_of_lemma::<T>();

    // Both posts have the same view by direct substitution.
    assert(post1_self_@ == pre_self_@.push(*new_value));
    assert(post2_self_@ == pre_self_@.push(*new_value));
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // *new_value is in both posts' views (push always contains the pushed element).
    assert(post1_self_@.contains(*new_value));
    assert(post2_self_@.contains(*new_value));

    // For every old value v in pre@, its position in pre@ equals its position in post@,
    // because pre@ has no duplicates and v != *new_value.
    assert forall|v: T| pre_self_@.contains(v) implies
        post1_self_@.index_of(v) == pre_self_@.index_of(v)
        && post2_self_@.index_of(v) == pre_self_@.index_of(v)
    by {
        if v != *new_value {
            assert(pre_self_@.push(*new_value).index_of(v) == pre_self_@.index_of(v));
        }
    }

    // Align value_list@ entries on the prefix [0, pre.len()) between pre, post1, post2.
    // For each i < pre.len(), instantiate the forall ensures at v = pre@[i].
    assert forall|i: int| 0 <= i < pre_self_.len() implies
        post1_self_.value_list@[i] == pre_self_.value_list@[i]
        && post2_self_.value_list@[i] == pre_self_.value_list@[i]
    by {
        let v = pre_self_@[i];
        assert(pre_self_@.contains(v));
        assert(v != *new_value);
        assert(pre_self_@.index_of(v) == i);
        assert(post1_self_@.contains(v));
        assert(post2_self_@.contains(v));
        assert(post1_self_@.index_of(v) == i);
        assert(post2_self_@.index_of(v) == i);
        // get_node_ref(v) unfolds (via the reveal at the top of det_push) to
        // value_list@[view.index_of(v)], so the forall ensures yield the entry equality.
        assert(pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
        assert(pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));
        assert(pre_self_.value_list@[i] == post1_self_.value_list@[i]);
        assert(pre_self_.value_list@[i] == post2_self_.value_list@[i]);
    }

    // r1, r2 are tied to post.value_list@ at the shared index of *new_value in the view.
    // post.value_list@.len() == post@.len() == pre.len() + 1 (from value_list_wf + wf).
    assert(post1_self_.value_list@.len() == pre_self_.len() + 1);
    assert(post2_self_.value_list@.len() == pre_self_.len() + 1);

    // r1 == post1.value_list@[post1@.index_of(*new_value)] and likewise for r2; views match
    // so the indices of *new_value match.
    assert(post1_self_@.index_of(*new_value) == post2_self_@.index_of(*new_value));
    assert(r1 == post1_self_.value_list@[post1_self_@.index_of(*new_value)]);
    assert(r2 == post2_self_.value_list@[post2_self_@.index_of(*new_value)]);

    // Conclude det_push_equal. The view equality is established; r1 == r2 follows once
    // z3 lines up the value_list@ entries at the matching index of *new_value, using the
    // prefix alignment plus the wf-disjointness of value_list and free_list across both
    // post states.
    assert(post1_self_.view() == post2_self_.view());
    assert(det_push_equal(r1, r2, post1_self_, post2_self_));
}
